mapper.update:
UPDATE member
name = #{name,jdbcType=VARCHAR}, gender = #{gender,jdbcType=TINYINT}, birthday = #{birthday,jdbcType=DATE}, email = #{email,jdbcType=VARCHAR}, address = #{address,jdbcType=VARCHAR}, status = #{status,jdbcType=TINYINT}, updated_time = NOW()
WHERE id = #{id,jdbcType=BIGINT}

mapper.select:
SELECT m.id, m.member_no, m.name, m.phone, m.password, m.gender, m.birthday, m.email, m.address, m.total_consumption, m.total_points, m.current_points, m.balance, m.register_store_id, m.status, m.last_consumption_time, m.login_count, m.last_login_time, m.last_login_ip, m.created_time, m.updated_time FROM member m LEFT JOIN store s ON m.register_store_id = s.id
AND m.name LIKE CONCAT('%', #{name}, '%')
AND m.phone LIKE CONCAT('%', #{phone}, '%')
AND m.member_no LIKE CONCAT('%', #{memberNo}, '%')
AND m.status = #{status}
AND s.store_name LIKE CONCAT('%', #{storeName}, '%')
AND m.gender = #{gender}
AND m.created_time >= #{startTime}
AND m.created_time <= #{endTime}
ORDER BY m.created_time DESC

mapper.update:
UPDATE member_card
SET current_points = #{points,jdbcType=INTEGER},
    total_points = #{totalPoints,jdbcType=INTEGER},
    updated_time = #{updateTime,jdbcType=TIMESTAMP}
WHERE member_id = #{memberId,jdbcType=BIGINT}

mapper.select:
SELECT COUNT(*)
FROM member
WHERE status = #{status,jdbcType=TINYINT}

SELECT COUNT(*)
FROM member
WHERE created_time >= #{startTime,jdbcType=TIMESTAMP}
  AND created_time <= #{endTime,jdbcType=TIMESTAMP}

SELECT COUNT(*)
FROM member


        AND register_store_id = #{storeId,jdbcType=BIGINT}


        AND created_time >= #{startTime,jdbcType=TIMESTAMP}


        AND created_time <= #{endTime,jdbcType=TIMESTAMP}

    AND status = 1

SELECT
    DATE(created_time) as date,
    COUNT(*) as newMembers,
    SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) as activeMembers
FROM member


        AND register_store_id = #{storeId,jdbcType=BIGINT}


        AND created_time >= #{startDate,jdbcType=TIMESTAMP}


        AND created_time <= #{endDate,jdbcType=TIMESTAMP}


GROUP BY DATE(created_time)
ORDER BY DATE(created_time) ASC
